mapper.select:
SELECT `t1`.`id` AS `id`, `t1`.`user_id` AS `userId`, `t1`.`title` AS `title`, `t1`.`content` AS `content`, `t1`.`like_count` AS `likeCount`, `t1`.`comment_count` AS `commentCount`, `t1`.`created_at` AS `createdAt`, `t1`.`updated_at` AS `updatedAt`, `t2`.`nickname` AS `nickname` FROM `pet_log`.`feed` AS `t1` LEFT JOIN `pet_log`.`personal_user` AS `t2` ON `t1`.`user_id` = `t2`.`user_id`
id < #{lastFeedId}
ORDER BY id DESC LIMIT #{size}
